function EnergyMonitor() {
  const [kwh, setKwh] = React.useState(12.4);
  const [solar, setSolar] = React.useState(8.2);
  const [cost, setCost] = React.useState(1.86);

  React.useEffect(() => {
    const interval = setInterval(() => {
      setKwh(k => Math.round((k + Math.random() * 0.3) * 10) / 10);
      setSolar(s => Math.round((Math.max(0, s + (Math.random() - 0.4) * 0.5)) * 10) / 10);
      setCost(c => Math.round((c + Math.random() * 0.05) * 100) / 100);
    }, 10000);
    return () => clearInterval(interval);
  }, []);

  const cards = [
    { label: 'Used Today', value: kwh + ' kWh', color: '#f59e0b', icon: '⚡' },
    { label: 'Solar Gen', value: solar + ' kWh', color: '#10b981', icon: '☀️' },
    { label: 'Est. Cost', value: '$' + cost.toFixed(2), color: '#ef4444', icon: '💰' },
    { label: 'Net Grid', value: (kwh - solar > 0 ? '+' : '') + (kwh - solar).toFixed(1) + ' kWh', color: '#3b82f6', icon: '🔌' }
  ];

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', padding: 16, borderRadius: 8, boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, color: '#9ca3af' }}>Energy Dashboard</div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, flex: 1 }}>
        {cards.map((c, i) => (
          <div key={i} style={{ background: '#1f2937', borderRadius: 8, padding: 14, display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', gap: 6 }}>
            <span style={{ fontSize: 24 }}>{c.icon}</span>
            <span style={{ fontSize: 20, fontWeight: 700, color: c.color }}>{c.value}</span>
            <span style={{ fontSize: 11, color: '#9ca3af' }}>{c.label}</span>
          </div>
        ))}
      </div>
      <div style={{ marginTop: 10, height: 8, background: '#1f2937', borderRadius: 4, overflow: 'hidden' }}>
        <div style={{ width: Math.min(100, (solar / (kwh || 1)) * 100) + '%', height: '100%', background: '#10b981', borderRadius: 4, transition: 'width 1s' }} />
      </div>
      <div style={{ fontSize: 10, color: '#6b7280', marginTop: 4, textAlign: 'center' }}>Solar coverage</div>
    </div>
  );
}
render(<EnergyMonitor/>);
